# -*- coding: utf-8 -*-"""Grever 故障恢复脚本 (reins/recovery.py)清理卡住的任务 + 回收离线 Worker 的任务"""import asynciofrom loguru import loggerfrom datetime import datetime, timedeltafrom models.task import Taskfrom models.agent import Agentfrom reins.scheduler.statemachine import transition_task_statusVERIFICATION_TIMEOUT_HOURS = 1BLOCK_TIMEOUT_HOURS = 24OFFLINE_THRESHOLD_MINUTES = 90def cleanup_zombie_tasks(db_session):    """清理僵尸任务: verifying/bocked/timeout 超过阈值 -> 重置为 todo"""    now = datetime.now()    cleaned = []    verifying_deadline = now - timedelta(hours=VERIFICATION_TIMEOUT_HOURS)    zombie_v = (        db_session.query(Task)        .filter(Task.status == 'verifying', Task.updated_at < int(verifying_deadline.timestamp()))        .all()    )    if zombie_v:        for task in zombie_v:            try:                transition_task_status(                    db_session, task, 'todo',                    reason=f"zombie cleanup: verifying 超过 {VERIFICATION_TIMEOUT_HOURS}h",                    extra={"assigned_agent": None},                )                logger.info(f"  [CLEAN] verifying: {task.id} agent={task.assigned_agent}")            except Exception as e:                logger.warning(f"  [CLEAN] verifying failed: {task.id}: {e}")        cleaned.append(f'verifying: {len(zombie_v)} tasks -> todo')    block_deadline = now - timedelta(hours=BLOCK_TIMEOUT_HOURS)    zombie_b = (        db_session.query(Task)        .filter(            Task.status.in_(['blocked', 'timeout']),            Task.updated_at < int(block_deadline.timestamp()),        )        .all()    )    if zombie_b:        for task in zombie_b:            try:                transition_task_status(                    db_session, task, 'todo',                    reason=f"zombie cleanup: {task.status} 超过 {BLOCK_TIMEOUT_HOURS}h",                    extra={"assigned_agent": None},                )                logger.info(f"  [CLEAN] {task.status}: {task.id}")            except Exception as e:                logger.warning(f"  [CLEAN] {task.status} failed: {task.id}: {e}")        cleaned.append(f'blocked/timeout: {len(zombie_b)} tasks -> todo')    db_session.commit()    return cleaneddef recover_offline_agents(db_session, offline_threshold_minutes=OFFLINE_THRESHOLD_MINUTES):    """回收离线 Worker 的任务"""    deadline = datetime.now() - timedelta(minutes=offline_threshold_minutes)    recovered = []    offline_list = (        db_session.query(Agent)        .filter(Agent.last_heartbeat < int(deadline.timestamp()), Agent.status != 'offline')        .all()    )    if not offline_list:        logger.info("  [RECOVER] no offline agents found")        return recovered    for agent in offline_list:        agent_id = agent.id        agent_name = agent.name        old_status = agent.status        last_hb = agent.last_heartbeat        logger.info(f"  [RECOVER] agent={agent_name} (id={agent_id}) last_hb={last_hb} status={old_status}")        stuck_tasks = (            db_session.query(Task)            .filter(Task.assigned_agent == agent_id, Task.status.in_(['in_progress', 'verifying']))            .all()        )        if stuck_tasks:            for task in stuck_tasks:                try:                    transition_task_status(                        db_session, task, 'todo',                        reason=f"offline agent recovery: agent {agent_name} went offline",                        extra={"assigned_agent": None},                    )                    logger.info(f"    [RECOVER] task={task.id} status={task.status}")                except Exception as e:                    logger.warning(f"    [RECOVER] task failed: {task.id}: {e}")            recovered.append(f'{agent_name}: {len(stuck_tasks)} tasks')        agent.status = 'offline'        agent.updated_at = int(datetime.now().timestamp())        logger.info(f"  [RECOVER] marked {agent_name} as offline")    db_session.commit()    return recovereddef start_periodic_recovery(interval_seconds: int = 300):    """启动周期性心跳超时自动回收任务。"""    async def _periodic_loop():        while True:            try:                from reins.common.database import get_db_session                db = get_db_session()                try:                    cleaned = cleanup_zombie_tasks(db)                    for msg in cleaned:                        logger.info(f"[PeriodicRecovery] Cleanup: {msg}")                    recovered = recover_offline_agents(db)                    for msg in recovered:                        logger.info(f"[PeriodicRecovery] Recover: {msg}")                    if not cleaned and not recovered:                        logger.debug("[PeriodicRecovery] No zombie tasks or offline agents found")                finally:                    db.close()            except Exception as e:                logger.error(f"[PeriodicRecovery] Error during periodic recovery: {e}")            await asyncio.sleep(interval_seconds)    asyncio.create_task(_periodic_loop(), name="periodic-recovery")    logger.info(f"[PeriodicRecovery] Started with interval={interval_seconds}s")if __name__ == '__main__':    import sys    from pathlib import Path    src_root = Path(__file__).resolve().parent.parent    sys.path.insert(0, str(src_root))    sys.stdout.reconfigure(encoding='utf-8')    from reins.common.database import get_db_session    logger.info('=' * 60)    logger.info('Sprint 61.1: Zombie Task Cleanup + Offline Worker Recovery')    logger.info(f'Time: {datetime.now().strftime("%Y-%m-%d %H:%M:%S")}')    logger.info('=' * 60)    db = get_db_session()    try:        logger.info('\n[1] Cleanup zombie tasks...')        cleaned = cleanup_zombie_tasks(db)        if cleaned:            for msg in cleaned:                logger.info(f'  Done: {msg}')        else:            logger.info('  No zombie tasks found')        logger.info('\n[2] Recover offline agents...')        recovered = recover_offline_agents(db)        if recovered:            for msg in recovered:                logger.info(f'  Done: {msg}')        else:            logger.info('  No offline agents found')        logger.info('\n[3] Verify final state...')        from sqlalchemy import func        task_status_counts = (            db.query(Task.status, func.count(Task.id))            .group_by(Task.status)            .order_by(func.count(Task.id).desc())            .all()        )        logger.info('  Task status:')        for status_val, count in task_status_counts:            logger.info(f'    {status_val:20s}: {count}')        agents = db.query(Agent).order_by(Agent.name).all()        logger.info('  Agent status:')        for a in agents:            logger.info(f'    {a.id:10s} name={a.name:10s} status={a.status:10s} last_hb={a.last_heartbeat}')        logger.info('\n[Sprint 61.1] Cleanup completed successfully')    finally:        db.close()